column6:
{
  "note": "Provide close substitute options for sriracha so you can keep the same flavor profile when shopping.",
  "alts": [
    {
      "name_en": "Huy Fong Foods Sriracha (regular)",
      "match": "Very close",
      "desc": "Classic rooster logo sriracha with the familiar sweet-heat chili-garlic flavor used in most sriracha recipes.",
      "where": "Asian aisle, condiment shelf (hot sauces)"
    },
    {
      "name_en": "Lee Kum Kee Chili Garlic Sauce",
      "match": "Similar",
      "desc": "Garlic-forward chili sauce with a tangy, spicy kick that works well as a sriracha-style topping or stir-in.",
      "where": "Asian aisle, condiment shelf (chili sauces)"
    },
    {
      "name_en": "Flying Goose Sambal Oelek",
      "match": "Similar",
      "desc": "Straight chili heat with a pungent, garlicky-forward profile that substitutes for sriracha in many spicy dishes.",
      "where": "International/Asian aisle, condiment shelf (sambals)"
    },
    {
      "name_en": "Thai Kitchen Sweet Chili Sauce",
      "match": "Similar",
      "desc": "Sweeter chili sauce with bright vinegar notes that can replace sriracha when you want heat plus sweetness.",
      "where": "Asian aisle, condiment shelf (sweet chili)"
    }
  ]
}

{
  "note": "You need lactose-free butter-like options that still work for cooking and spreading despite lactose intolerance.",
  "alts": [
    {
      "name_en": "Lactaid Butter (Lactose-Free)",
      "match": "Very close",
      "desc": "Lactose-free butter that matches traditional butter texture and flavor while avoiding lactose.",
      "where": "Dairy/Butter section (lactose-free dairy aisle)"
    },
    {
      "name_en": "Challenge Dairy Lactose-Free Butter",
      "match": "Very close",
      "desc": "Butter made with reduced/removed lactose for people who are lactose intolerant.",
      "where": "Dairy/Butter section (lactose-free brand options)"
    },
    {
      "name_en": "Kerrygold (Lactose-Free) Butter",
      "match": "Very close",
      "desc": "A lactose-free version of a classic butter brand, providing familiar cooking and spreading performance.",
      "where": "Dairy/Butter section (specialty or lactose-free items)"
    },
    {
      "name_en": "Country Crock Plant Butter (Vegan, Lactose-Free)",
      "match": "Different but works",
      "desc": "Plant-based spread that is lactose-free and works for spreading and general cooking, though it may taste slightly different.",
      "where": "Refrigerated dairy-free/plant-based spread section"
    }
  ]
}

{
  "note": "You likely need substitutions that keep the same tangy flavor profile for cooking and pickling.",
  "alts": [
    {
      "name_en": "Unseasoned Rice Vinegar (different brand)",
      "match": "Very close",
      "desc": "Same product type (rice vinegar) with a similar mild, slightly sweet acidity to match your recipe.",
      "where": "Vinegar aisle (near other vinegars like white, apple cider, and balsamic)"
    },
    {
      "name_en": "Apple Cider Vinegar",
      "match": "Similar",
      "desc": "Different vinegar type but provides a comparable tangy acidity that works for marinades, dressings, and quick pickles.",
      "where": "Vinegar aisle"
    },
    {
      "name_en": "White Wine Vinegar",
      "match": "Similar",
      "desc": "Light, clean acidity that substitutes well in many sauces and dressings where rice vinegar’s mild bite is desired.",
      "where": "Vinegar aisle (often near champagne/white wine vinegars)"
    },
    {
      "name_en": "Champagne Vinegar",
      "match": "Similar",
      "desc": "Another mild, versatile vinegar that can stand in for rice vinegar when a gentle flavor is needed.",
      "where": "Vinegar aisle (specialty vinegar section)"
    }
  ]
}

{
  "note": "Need vegetarian substitutes for chicken breast for a comparable protein/texture role in North American grocery cooking.",
  "alts": [
    {
      "name_en": "Chicken-style tofu (extra-firm tofu cutlets)",
      "match": "Different but works",
      "desc": "Extra-firm tofu shaped or pre-seasoned like chicken provides a similar bite for grilling or pan-searing while staying fully vegetarian.",
      "where": "Produce/ Refrigerated tofu section (often near tofu tubs or prepared tofu cutlets)"
    },
    {
      "name_en": "Seitan (wheat gluten) cutlets",
      "match": "Different but works",
      "desc": "Seitan has a chewy, meat-like texture and can be sliced or pan-cooked to mimic chicken breast in sandwiches or stir-fries.",
      "where": "Refrigerated or refrigerated/frozen vegetarian meat alternatives aisle"
    },
    {
      "name_en": "Plant-based chicken breast (vegetarian “chicken” strips or cutlets)",
      "match": "Different but works",
      "desc": "Vegetarian plant-based chicken products are designed to replicate chicken breast flavor and texture for similar recipes.",
      "where": "Frozen or refrigerated vegetarian meat/plant-based aisle"
    },
    {
      "name_en": "Tempeh cutlets (soy tempeh, sliced and cooked)",
      "match": "Different but works",
      "desc": "Tempeh’s dense, satisfying texture works as a chicken-like protein substitute when marinated and seared.",
      "where": "Refrigerated specialty produce section near other fermented/soy products or refrigerated tofu/tempeh area"
    }
  ]
}

{
  "note": "You need substitutes for fish sauce that deliver a similar salty/umami backbone common in Korean cooking.",
  "alts": [
    {
      "name_en": "Saewoojeot (Salted Shrimp Brine) — Korean",
      "match": "Very close",
      "desc": "Korean salted shrimp brine/jeot provides deep savory umami and salinity that closely mimics fish sauce’s flavor role in soups, marinades, and dipping sauces.",
      "where": "Korean/international aisle or Korean market section (jarred/seasoned banchan/jeot items)"
    },
    {
      "name_en": "Gochujang (Fermented Chili Paste) — with Beef/Pork or Anchovy-based versions if sold",
      "match": "Similar",
      "desc": "Fermented gochujang adds rich umami and seasoning depth that can replace some fish-sauce “roundness” when mixed into soup/broth or marinades.",
      "where": "Korean foods aisle (gochujang tubs in condiments)"
    },
    {
      "name_en": "Korean Soy Sauce (Joseon Ganjang) — regular",
      "match": "Similar",
      "desc": "Soy sauce is not the same fish-derived product, but it provides salty, savory depth that works well in many Korean braises and stir-fries to approximate the seasoning effect.",
      "where": "Condiments aisle (soy sauce/cooking soy)"
    },
    {
      "name_en": "Oyster Sauce",
      "match": "Different but works",
      "desc": "Oyster sauce is seafood-based and delivers sweet-savory umami that can replace fish sauce in glazes and stir-fry seasonings, though it will taste less distinctly fishy.",
      "where": "Asian condiments aisle (oyster sauce near stir-fry sauces)"
    }
  ]
}
